const entrada = $json.body ?? $json;
const evento = entrada.eventType ?? $json.headers?.['x-emeu-evento'];
const payload = entrada.payload ?? {};
const reserva = payload.reserva ?? payload.cancelada ?? payload.promovida ?? null;
const peca = payload.peca ?? reserva?.peca ?? null;
const numero = String(reserva?.telefoneCliente ?? '').replace(/\D/g, '');
if (!numero) return [];
const telefone = numero.startsWith('244') ? numero : `244${numero}`;
const nome = reserva.nomeCliente || 'cliente';
const codigo = peca?.codigo || reserva.codigoPeca || '?';
const preco = peca?.precoEmKwanza ? new Intl.NumberFormat('pt-AO', { style: 'currency', currency: 'AOA', maximumFractionDigits: 0 }).format(peca.precoEmKwanza) : 'preço a confirmar';
const mensagens = {
  RESERVATION_CREATED: `Olá, ${nome}. Recebemos o teu pedido da peça #${codigo}.\n\nA peça ficou reservada temporariamente para ti.\nPreço: ${preco}\n\nApós o pagamento, envia o comprovativo por aqui.`,
  RESERVATION_EXPIRING: `Olá, ${nome}. A tua reserva da peça #${codigo} está quase a expirar. Envia o comprovativo para manter a prioridade.`,
  RESERVATION_WAITLISTED: `Olá, ${nome}. A peça #${codigo} já tem uma reserva ativa. Colocamos o teu pedido na fila de espera.`,
  RESERVATION_EXPIRED: `Olá, ${nome}. A reserva temporária da peça #${codigo} expirou porque o pagamento não foi confirmado dentro do prazo.`,
  PAYMENT_CONFIRMED: `Pagamento confirmado, ${nome}. A peça #${codigo} ficou marcada como paga. Obrigado pela compra!`,
  PAYMENT_REJECTED: `Olá, ${nome}. Não conseguimos validar o pagamento da peça #${codigo}. A equipa vai acompanhar contigo por aqui.`,
  ORDER_READY_TO_SHIP: `Olá, ${nome}. A encomenda da peça #${codigo} está pronta para envio.`,
  ORDER_DELIVERED: `Olá, ${nome}. A entrega da peça #${codigo} foi concluída. Obrigado por comprares connosco.`
};
const texto = mensagens[evento];
return texto ? [{ json: { telefone, texto, evento } }] : [];
